use rusoto_core::{client::Client, config::Config};
use rusoto_dynamodb::{DynamoDbClient, Table};

fn main() {
    let config = Config::builder()
        .region("us-east-1")
        .build()?;

    let client = DynamoDbClient::builder()
        .region(config.region())
        .build()?;

    let table = Table::builder()
        .table_name("ports")
        .build()?;

    let params = parse_port_params::default();

    let mut parser = parse_port::new(client, table);

    let parsed_port = parser.parse_port(&params)?;

    let russt_code = parser.russt_code(&params);

    let russt_code_output = russt_code.to_string();

    println!("Russt code: {:?}", russt_code_output);

    Ok(())
}

